parameters.functionCode:
// Calculate scaling requirements with budget limit
const currentMetrics = $input.first().json;
const currentOCPUs = 26; // Total from infrastructure
const scalePercent = 0.15; // 15% increase

// Budget constraints
const CURRENT_MONTHLY_COST = 900; // Current baseline
const MAX_MONTHLY_BUDGET = 1300; // Hard limit
const COST_PER_OCPU_MONTH = 0.0340 * 730; // E5.Flex pricing

const additionalOCPUs = Math.ceil(currentOCPUs * scalePercent / 2) * 2; // Round to even number
const estimatedNewCost = additionalOCPUs * COST_PER_OCPU_MONTH;
const projectedTotalCost = CURRENT_MONTHLY_COST + estimatedNewCost;

// Budget check - abort if would exceed limit
if (projectedTotalCost > MAX_MONTHLY_BUDGET) {
  return {
    json: {
      scaling_decision: {
        abort: true,
        reason: "budget_limit_exceeded",
        current_cost: CURRENT_MONTHLY_COST,
        projected_cost: projectedTotalCost.toFixed(2),
        budget_limit: MAX_MONTHLY_BUDGET,
        message: `Cannot scale: would exceed $${MAX_MONTHLY_BUDGET} budget (projected: $${projectedTotalCost.toFixed(2)})`
      }
    }
  };
}

const instanceShape = "VM.Standard.E5.Flex";

// Determine instance configuration
const newInstances = [];
const instanceCount = Math.ceil(additionalOCPUs / 4); // 4 OCPUs per instance

for (let i = 0; i < instanceCount; i++) {
  newInstances.push({
    shape: instanceShape,
    ocpus: 4,
    memory_gb: 16,
    display_name: `auto-scale-${Date.now()}-${i+1}`
  });
}

return {
  json: {
    scaling_decision: {
      abort: false,
      trigger: "capacity_threshold",
      current_ocpus: currentOCPUs,
      scale_percent: scalePercent * 100,
      additional_ocpus: additionalOCPUs,
      new_instances: newInstances,
      estimated_cost: estimatedNewCost.toFixed(2),
      current_monthly_cost: CURRENT_MONTHLY_COST,
      projected_monthly_cost: projectedTotalCost.toFixed(2),
      budget_limit: MAX_MONTHLY_BUDGET,
      budget_remaining: (MAX_MONTHLY_BUDGET - projectedTotalCost).toFixed(2),
      triggered_by: currentMetrics
    }
  }
};

// Find auto-scaled instances with low utilization
const threshold = 30; // Scale down if below 30% for sustained period

return {
  json: {
    action: "scale_down",
    message: "Instance utilization below threshold for scale down"
  }
};

